SELECT font_family, font_size
FROM typography
WHERE site_id = 0;

SELECT site_name
FROM sites
ORDER BY site_name;

SELECT AVG(value) AS average_value
FROM website_performance
WHERE site_id = 1 AND metric = 'page views';

SELECT element_name
FROM design_elements
WHERE element_id = 1;

SELECT AVG(value) AS average_page_views
FROM website_performance
WHERE metric = 'page views' AND date = '2023-01-01';

SELECT COUNT(DISTINCT customization_type) AS customization_types_count
FROM site_customizations
WHERE site_id = 1;

SELECT COUNT(DISTINCT site_id) AS customization_count
FROM site_customizations
WHERE user_id = 1;
